244	+import { describe, expect, test } from 'effect-bun-test';
245	+import { Result, Schema } from 'effect';
246	+
247	+import { defaultContent } from './defaults';
248	+import { backfillListItemIds } from './id-backfill';
249	+import { SiteContent } from './schema';
250	+
251	+/**
252	+ * The read-path id-backfill is the production read-safety hinge of ADR 0006:
253	+ * adding a *required* `id` to every list item would make every already-published
254	+ * `content/site.json` (which has no ids) FAIL decode on read — breaking the live
255	+ * site on the deploy. `backfillListItemIds` runs between parse and decode and
256	+ * assigns a fresh `nanoid` to any id-less item, so the legacy document decodes.
257	+ * These tests pin that property, its idempotence, and that it never mints over
258	+ * an existing id.
259	+ */
260	+
261	+type JsonRecord = Record<string, unknown>;
262	+
263	+/** The encoded (plain-JSON) form of the bundled defaults — a real test base. */
264	+const encodedDefaults = (): JsonRecord =>
265	+  Schema.encodeUnknownSync(SiteContent)(defaultContent) as JsonRecord;
266	+
267	+const decodes = (value: unknown): boolean =>
268	+  Result.isSuccess(Schema.decodeUnknownResult(SiteContent)(value));
269	+
270	+/** A deep clone the test can mutate without disturbing the shared default. */
271	+const clone = (value: JsonRecord): JsonRecord =>
272	+  JSON.parse(JSON.stringify(value)) as JsonRecord;
273	+
274	+/** Strip every list-item `id` — the shape a document published BEFORE ids had. */
275	+const stripIds = (encoded: JsonRecord): JsonRecord => {
276	+  const doc = clone(encoded);
277	+  for (const conference of (doc['conferences'] as JsonRecord[]) ?? []) {
278	+    for (const listKey of ['speakers', 'seminars']) {
279	+      for (const item of (conference[listKey] as JsonRecord[]) ?? []) {
280	+        delete item['id'];
281	+      }
282	+    }
283	+  }
284	+  for (const member of (doc['team'] as JsonRecord[]) ?? []) {
285	+    delete member['id'];
286	+  }
287	+  return doc;
288	+};
289	+
290	+const idsOf = (doc: unknown): string[] => {
291	+  const out: string[] = [];
292	+  const record = doc as JsonRecord;
293	+  for (const conference of (record['conferences'] as JsonRecord[]) ?? []) {
294	+    for (const listKey of ['speakers', 'seminars']) {
295	+      for (const item of (conference[listKey] as JsonRecord[]) ?? []) {
296	+        if (typeof item['id'] === 'string') out.push(item['id']);
297	+      }
298	+    }
299	+  }
300	+  for (const member of (record['team'] as JsonRecord[]) ?? []) {
301	+    if (typeof member['id'] === 'string') out.push(member['id']);
302	+  }
303	+  return out;
304	+};
305	+
306	+describe('backfillListItemIds — production read-safety (ADR 0006)', () => {
307	+  test('an id-less document (the pre-migration shape) decodes after backfill', () => {
308	+    const idLess = stripIds(encodedDefaults());
309	+
310	+    // Sanity: WITHOUT backfill the legacy document fails decode — this is the
311	+    // hazard the backfill exists to prevent.
312	+    expect(decodes(idLess)).toBe(false);
313	+
314	+    // WITH backfill it decodes — the deploy does not break the live site.
315	+    const repaired = backfillListItemIds(idLess);
316	+    expect(decodes(repaired)).toBe(true);
317	+  });
318	+
319	+  test('assigns a fresh, distinct id to every id-less list item', () => {
320	+    const idLess = stripIds(encodedDefaults());
321	+    expect(idsOf(idLess)).toHaveLength(0);
322	+
323	+    const repaired = backfillListItemIds(idLess);
324	+    // 2024 has 2 speakers + 3 seminars; team has 3 members = 8 ids.
325	+    expect(idsOf(repaired)).toHaveLength(8);
326	+    expect(new Set(idsOf(repaired)).size).toBe(8);
327	+  });
328	+
329	+  test('is idempotent — re-running leaves an already-id-complete document untouched', () => {
330	+    const encoded = encodedDefaults();
331	+    // The defaults already carry ids; backfill must change nothing.
332	+    expect(backfillListItemIds(encoded)).toEqual(encoded);
333	+
334	+    // And a freshly-backfilled document is a fixed point.
335	+    const once = backfillListItemIds(stripIds(encoded));
336	+    const twice = backfillListItemIds(once);
337	+    expect(twice).toEqual(once);
338	+  });
339	+
340	+  test('never mints over an existing id (a partial document keeps its ids)', () => {
341	+    const encoded = encodedDefaults();
342	+    const allIds = idsOf(encoded);
