387	+/**
388	+ * Read-path id-backfill normalization (ADR 0006 consequence, registration-launch
389	+ * Branch 2 sub-commit 2.1).
390	+ *
391	+ * Every CMS list item now carries a *required* `id: ListItemId` (a `nanoid`) so
392	+ * the editor can address it by identity rather than by array position. But every
393	+ * `content/site.json` already published BEFORE this change has no ids, so a
394	+ * required `id` would make the live document FAIL decode on the next read — the
395	+ * deploy would break the public site on its own content.
396	+ *
397	+ * The fix is a one-shot repair at the read boundary: before the document is
398	+ * Schema-decoded, `backfillListItemIds` walks the parsed (untrusted) JSON and
399	+ * assigns a fresh `nanoid` to any list item that lacks an `id`. It is a pure
400	+ * structural normalization — NOT a parallel schema and NOT validation:
401	+ *   - `derive-dont-sync`: there is one decode boundary; this only fills the gap
402	+ *     a pre-ids document leaves, so the decoded value is always id-complete.
403	+ *   - `make-operations-idempotent`: an item that already has an `id` key is left
404	+ *     untouched (even a *bad* id is left for the decoder to reject — backfill is
405	+ *     for absence, not repair), so re-running on an already-migrated document is
406	+ *     a no-op. The first admin publish persists the backfilled ids; from then on
407	+ *     the normalization changes nothing.
408	+ *   - `boundary-discipline`: it runs only over already-parsed JSON inside the
409	+ *     read path, never mutates its input, and hands a fresh value to the decoder
410	+ *     which remains the sole gate that brands the ids. The input is `unknown`
411	+ *     (raw parsed JSON), so the walk narrows defensively and never trusts shape.
412	+ *
413	+ * The list-item locations are the three id-bearing structs the schema names
414	+ * today (`Speaker`, `Seminar`, `TeamMember`); Branch 3+ widens them as the
415	+ * Conference / Page schemas grow id-bearing lists, and this walk grows with
416	+ * them. The walk descends only into the arrays/objects that are actually present
417	+ * and the expected shape, so a malformed document still reaches the decoder
418	+ * (which rejects it) rather than throwing here.
419	+ */
420	+
421	+import { newListItemId } from './schema';
422	+import type { Json } from './admin-form';
423	+
424	+const isObject = (value: unknown): value is { readonly [key: string]: Json } =>
425	+  typeof value === 'object' && value !== null && !Array.isArray(value);
426	+
427	+/** Assign a fresh id to a list item that has no `id` key; else leave it alone. */
428	+const withId = (item: Json): Json => {
429	+  if (!isObject(item)) return item;
430	+  if ('id' in item) return item;
431	+  return { id: newListItemId(), ...item };
432	+};
433	+
434	+/** Backfill ids on every element of `value` when it is an array of items. */
435	+const backfillItems = (value: unknown): readonly Json[] | undefined =>
436	+  Array.isArray(value) ? value.map(withId) : undefined;
437	+
438	+/**
439	+ * Return a copy of the parsed `SiteContent` JSON with a fresh id assigned to any
440	+ * id-less list item (`conferences[].speakers[]`, `conferences[].seminars[]`,
441	+ * `team[]`). Items already carrying an `id` are untouched (idempotent). A value
442	+ * that is not the expected shape is returned as-is so the decoder — not this
443	+ * normalizer — is the one to reject it.
444	+ */
445	+export const backfillListItemIds = (document: unknown): unknown => {
446	+  if (!isObject(document)) return document;
447	+
448	+  const next: Record<string, Json> = { ...document };
449	+
450	+  const conferences = document['conferences'];
451	+  if (Array.isArray(conferences)) {
452	+    next['conferences'] = conferences.map((conference: Json) => {
453	+      if (!isObject(conference)) return conference;
454	+      const conf: Record<string, Json> = { ...conference };
455	+      const speakers = backfillItems(conference['speakers']);
456	+      if (speakers !== undefined) conf['speakers'] = speakers;
457	+      const seminars = backfillItems(conference['seminars']);
458	+      if (seminars !== undefined) conf['seminars'] = seminars;
459	+      return conf;
460	+    });
461	+  }
462	+
463	+  const team = backfillItems(document['team']);
464	+  if (team !== undefined) next['team'] = team;
465	+
466	+  return next;
467	+};
