243	  test('decode/make produce a branded value, and a raw string is not assignable', () => {
244	    // Decoding yields the branded type, assignable to its own brand…
245	    const key: AssetKeyType = AssetKey.make('2026/en/hero.png');
246	    const date: IsoDateType = IsoDate.make('2026-06-10');
247	    const colour: HexColourType = HexColour.make('#D4A24E');
