259	    // is a deliberate type error guarded by `@ts-expect-error`, so the typecheck
260	    // fails if branding is ever lost (`prove-it-works` at the type level).
261	    // @ts-expect-error a raw string is not an AssetKey until it crosses the decoder
262	    const notKey: AssetKeyType = '2026/en/hero.png';
263	    // @ts-expect-error a raw string is not an IsoDate until it crosses the decoder
