270	    const notItemId: ListItemIdType = 'YOQ7GeACwaTCKjY6y3HAV';
271	
272	    // Reference the locals so they are not flagged as unused; their string
273	    // values are intentionally identical to the branded ones above (widen to
274	    // base string so the matcher compares plain strings).
275	    expect([notKey, notDate, notColour, notSlug, notItemId].map(String)).toEqual([
276	      '2026/en/hero.png',
277	      '2026-06-10',
278	      '#D4A24E',
279	      '/2026',
