247	const selectCurrent = (
248	  content: SiteContentType,
249	  locale: Locale,
250	  now: number,
251	): Conference => {
252	  const index = content.conferences.findIndex((conference) =>
253	    dayjs(now).isBefore(toEndOfDayMs(conference.dates.start)),
254	  );
255	  const conference =
256	    index === -1 ? content.conferences[content.conferences.length - 1] : content.conferences[index];
