272	  // selector and the schema invariant agree (`derive-dont-sync`) and any
273	  // year the routes serve is guaranteed present by the time we get here.
274	  const conference = content.conferences.find(
275	    (candidate) => candidate.slug === `/${year}`,
276	  );
