307	/**
308	 * Cache TTL. Short by design (D3 — runtime read with cache, no redeploy): a
309	 * publish becomes visible on the next read after the TTL elapses (or the
310	 * editor's explicit `bust`). 30s keeps the bucket-read rate negligible while
311	 * making edits feel near-instant.
312	 */
313	const CACHE_TTL_MS = 30_000;
314	
315	/**
316	 * Parse a `content/site.json` string and decode it to a `SiteContent`, running
317	 * the id-backfill normalization between parse and decode so a document
318	 * published before list-item ids existed (ADR 0006) still decodes — every id-less
319	 * list item gets a fresh `nanoid` before the required `id` field is checked. The
320	 * two-step (parse → backfill → decode), rather than a single `fromJsonString`,
321	 * is what lets the normalization see the parsed value before validation.
322	 */
323	const parseJson = Schema.decodeUnknownEffect(
324	  Schema.fromJsonString(Schema.Unknown),
325	);
326	const decodeSiteContent = Schema.decodeUnknownEffect(SiteContent);
327	const decodeDocument = (json: string) =>
328	  parseJson(json).pipe(
329	    Effect.map(backfillListItemIds),
330	    Effect.flatMap(decodeSiteContent),
331	  );
