346	      readonly team: readonly TeamMember[];
347	      readonly board: readonly string[];
348	    }>;
349	    /**
350	     * Invalidate the public read cache so a subsequent `getSiteContent`
351	     * re-reads the bucket. Called by the editor's publish action so a publish
352	     * is visible with no redeploy and without waiting out the TTL (D3,
353	     * `make-operations-idempotent` — busting an already-empty cache is a no-op).
354	     * When no refresh is already in flight a publish is visible on the very
355	     * next read; otherwise it is visible within the documented staleness window
356	     * — `invalidate` only expires the entry, it does not pre-empt an in-flight
357	     * refresh (see the `Content` doc above for the full mechanism).
358	     */
359	    readonly bust: () => Effect.Effect<void>;
360	  }
361	>()('gycc/lib/content.server/Service') {}
