363	/**
364	 * The `Content` layer (opencode's module-level `export const layer`,
365	 * `packages/core/src/git.ts:79`), leaving its `Storage` requirement open so the
366	 * app runtime and tests can supply different `Storage` layers. `defaultLayer`
367	 * pre-provides `Storage.layerOptional` (the never-fails-to-build storage,
368	 * mirroring `git.ts:347`), leaving only `Env` open — the public read path is
369	 * thus wired with a single `Content.defaultLayer` in the runtime, with `Env`
370	 * discharged by the surrounding merge.
371	 */
372	export const layer = Layer.effect(
373	  Service,
374	  Effect.gen(function* () {
375	    const storage = yield* Storage.Service;
376	
377	    /**
378	     * Read + decode the `SiteContent` document at `key`, or `Option.none()`
379	     * when it is absent / unreadable / malformed. Shared by the public read
380	     * path (which maps `none` to the bundled defaults) and the admin read
381	     * path (which tries the draft, then the published key, then defaults).
382	     */
383	    const readDocument = Effect.fnUntraced(
384	      function* (key: string) {
385	        const object = yield* storage.get(key);
386	        const json = yield* Effect.promise(() =>
387	          new Response(object.stream).text(),
388	        );
389	        return Option.some(yield* decodeDocument(json));
390	      },
391	      (effect, key) =>
392	        effect.pipe(
393	          Effect.catchCause((cause) =>
394	            Effect.logWarning(`Content: could not read ${key}`, cause).pipe(
395	              Effect.as(Option.none<SiteContentType>()),
396	            ),
397	          ),
398	        ),
399	    );
400	
401	    /**
402	     * Read + decode the document from the bucket, falling back to the bundled
403	     * defaults on every failure mode (`boundary-discipline`, D3):
404	     *   - no bucket configured → `Storage.layerOptional` yields a disabled
405	     *     storage whose `get` reports `NotFound`;
406	     *   - object absent / empty → `NotFound`;
407	     *   - bucket unreachable or document malformed → any other failure /
408	     *     decode error / unexpected defect.
409	     * In all cases `readDocument` logs and yields `none`, so the site is never
410	     * broken by a missing or bad document — the public read always gets a
411	     * `SiteContent`.
412	     */
413	    const fetchDocument: Effect.Effect<SiteContentType> = readDocument(
414	      SITE_CONTENT_KEY,
415	    ).pipe(
416	      Effect.map((document) =>
417	        Option.getOrElse(document, () => defaultContent),
418	      ),
419	    );
420	
421	    /**
422	     * The public read cache: Effect's built-in TTL cache with manual
423	     * invalidation (`use-the-platform`). `cachedContent` single-flights
424	     * concurrent first-reads onto one `fetchDocument` (the others park on its
425	     * latch and share the result, so the bucket is not stampeded) and returns
426	     * the same decoded `SiteContent` reference for the TTL's duration;
427	     * `invalidate` arms the next read to re-fetch (the editor's publish path).
428	     */
429	    const [cachedContent, invalidate] = yield* Effect.cachedInvalidateWithTTL(
430	      fetchDocument,
431	      Duration.millis(CACHE_TTL_MS),
432	    );
433	
434	    const getSiteContent = Effect.fn('Content.getSiteContent')(function* () {
435	      return yield* cachedContent;
436	    });
