333	/** The deleted inline algorithm, reproduced verbatim, returning the stored JSON. */
334	const inlineOracle = (
335	  current: SiteContentType,
336	  entries: ReadonlyArray<readonly [string, string]>,
337	) =>
338	  Effect.gen(function* () {
339	    const base = (yield* encodeObject(current)) as Json;
340	    const overrides = assembleOverrides(entries);
341	    const translations = collectTranslations(entries);
342	    const merged = deepMerge(deepMerge(base, overrides), {
343	      translations,
344	    } as Json);
345	    const decoded = yield* decodeMerged(merged);
346	    return yield* encodeObjectJson(decoded);
347	  });
